mapper.update:
UPDATE public."SanmingTobaccoProductionSituation"
SET
    "Area" = #{area},
    "Contract Quantity" = #{contractQuantity},
    "Acquisition Volume" = #{acquisitionVolume},
    "Tobacco farming households" = #{tobaccoFarming},
    "Tobacco technicians" = #{tobaccoTechnic},
    "Roasting rooms" = #{roastingRooms},
    "Seedling Shelters" = #{seedlingShelter},
    "Remarks" = #{remarks}
WHERE
    "Year" = #{year}
  AND "CountyDistrict" = #{countyDistrict}
  AND "Town" = #{town}
  AND "Village" = #{village}

mapper.delete:
DELETE FROM public."SanmingTobaccoProductionSituation"
WHERE "Year" = #{year}
  AND "CountyDistrict" = #{countyDistrict}
  AND "Town" = #{town}
  AND "Village" = #{village}
